export const FoundationWallet = Contracts.Import("FoundationWallet");
export type FoundationWallet = Exact<typeof FoundationWallet>;
export const NightProtocolParams = Contracts.Import("NightProtocolParams");
export type NightProtocolParams = Exact<typeof NightProtocolParams>;
export const UpgradeParamsAction = Contracts.Import("UpgradeParamsAction");
export type UpgradeParamsAction = Exact<typeof UpgradeParamsAction>;

export class MultisigMultisigElse {
  public Script: Script
  constructor(
    protocolParamsPolicy: PolicyId,
  ) {
    this.Script = cborToScript(
      applyParamsToScript(
        "",
        Type.Tuple([
          PolicyId,
        ]),
        [
          protocolParamsPolicy,
        ],
      ),
      "PlutusV3"
    );
  }
}
export class ProtocolParamsProtocolParamsSpend {
  public Script: Script
  constructor(
    oneShot: OutputReference,
  ) {
    this.Script = cborToScript(
      applyParamsToScript(
        "",
        Type.Tuple([
          Type.Object({
            transaction_id: Type.String(),
            output_index: Type.BigInt(),
          }, { ctor: 0n }),
        ]),
        [
          oneShot,
        ],
      ),
      "PlutusV3"
    );
  }
}
